class InteractionTracker:
    def __init__(self):
        self.interactions = {}
        self.user_data = {}

    def _hash_user_id(self, user_id):
        import hashlib
        return hashlib.sha256(user_id.encode()).hexdigest()

    def add_user(self, user_id):
        hashed_id = self._hash_user_id(user_id)
        if hashed_id not in self.user_data:
            self.user_data[hashed_id] = {
                'likes': [],
                'ratings': [],
                'uploads': [],
                'settings_changes': []
            }

    def track_interaction(self, user_id, interaction_type, interaction_data):
        hashed_id = self._hash_user_id(user_id)
        if hashed_id not in self.user_data:
            self.add_user(user_id)

        if interaction_type not in self.user_data[hashed_id]:
            raise ValueError("Unsupported interaction type")

        self.user_data[hashed_id][interaction_type].append(interaction_data)

    def get_user_interactions(self, user_id):
        hashed_id = self._hash_user_id(user_id)
        return self.user_data.get(hashed_id, None)

    def add_interaction_type(self, interaction_type):
        for user in self.user_data.values():
            if interaction_type not in user:
                user[interaction_type] = []

# Example usage
tracker = InteractionTracker()
tracker.track_interaction('user123', 'likes', {'item_id': 'item456'})
tracker.track_interaction('user123', 'ratings', {'item_id': 'item456', 'rating': 5})
print(tracker.get_user_interactions('user123'))

