        user = self.get_user(user_id)
        if user:
            rating = Rating(item_id, score, comment)
            user.add_rating(rating)

    def update_user_setting(self, user_id, key, value):
        user = self.get_user(user_id)
        if user:
            user.update_setting(key, value)

    def anonymize_user_data(self, user_id):
        user = self.get_user(user_id)
        if user:
            user.email = "anonymized@example.com"
            user.username = "User_" + str(user.user_id)

