def process_data(data):
    processed = []
    for item in data:
        if isinstance(item, dict):
            processed.append({k: v for k, v in item.items() if v is not None})
        elif isinstance(item, list):
            processed.append([v for v in item if v is not None])
        else:
            processed.append(item)
    return processed

def calculate_ratings(data):
    ratings = []
    for item in data:
        if isinstance(item, dict) and 'rating' in item:
            ratings.append(item['rating'])
    return sum(ratings) / len(ratings) if ratings else 0

def filter_data(data, threshold):
    return [item for item in data if isinstance(item, dict) and item.get('value', 0) > threshold]

